% Description:
%
% This script demonstrates basic execution of en_cl_fix functions in MATLAB, using MATLAB's native
% Python support.
%
% This script covers "narrow" (<= 53 bits) fixed-point numbers.
% -------------------------------------------------------------------------------------------------

%--------------------------------------------------------------------------------------------------
% Copyright (c) 2024 Enclustra GmbH, Switzerland (info@enclustra.com)
% 
% Permission is hereby granted, free of charge, to any person obtaining a copy of this software
% and associated documentation files (the "Software"), to deal in the Software without
% restriction, including without limitation the rights to use, copy, modify, merge, publish,
% distribute, sublicense, and/or sell copies of the Software, and to permit persons to whom the
% Software is furnished to do so, subject to the following conditions:
% 
% The above copyright notice and this permission notice shall be included in all copies or
% substantial portions of the Software.
% 
% THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR IMPLIED, INCLUDING
% BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE AND
% NONINFRINGEMENT. IN NO EVENT SHALL THE AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM,
% DAMAGES OR OTHER LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,
% OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE SOFTWARE.
%--------------------------------------------------------------------------------------------------

% -------------------------------------------------------------------------------------------------
% Environment Setup
% -------------------------------------------------------------------------------------------------
close all; clear all; clc;

% None of the documented methods for reloading en_cl_fix_pkg "in-process" work. Therefore, if we
% want to modify Python sources without restarting MATLAB, then we must execute Python "out of
% process". This is much slower to execute, but useful for debugging.
RELOAD_PYTHON_MODULES = false;
pe = pyenv;
if RELOAD_PYTHON_MODULES
    if strcmp(pe.Status, 'Loaded') && strcmp(pe.ExecutionMode, 'InProcess')
        error('MATLAB must be restarted to change the Python environment');
    end
    terminate(pe);
    pe = pyenv(ExecutionMode='OutOfProcess');
else
    if strcmp(pe.Status, 'NotLoaded')
        pe = pyenv(ExecutionMode='InProcess');
    else
        if strcmp(pe.ExecutionMode, 'OutOfProcess')
            error('MATLAB must be restarted to change the Python environment');
        end
    end
end

% Sanity check: Make sure MATLAB can find a Python installation.
assert(pe.Version ~= "", "Python installation not detected by MATLAB.");
disp(append('Detected Python version: ', pe.Version, '.'));

% Add Python sources to the Python path.
root = fileparts(mfilename('fullpath'));
python_src_path = fullfile(root, '..', '..', 'models', 'python');
insert(py.sys.path, int32(0), python_src_path);

% Load the en_cl_fix Python package.
py.importlib.import_module('en_cl_fix_pkg');

% Add MATLAB sources to MATLAB path
addpath(fullfile(root, '..', '..', 'models', 'matlab'));

% -------------------------------------------------------------------------------------------------
% Example Setup
% -------------------------------------------------------------------------------------------------

% Load shorthand constants
cl_fix_constants;

% Specify some input data formats.
a_fmt = cl_fix_format(1, 0, 15);
b_fmt = cl_fix_format(0, 2, 6);

% Check string conversion functions
disp(append('a_fmt = ', cl_fix_format_to_string(a_fmt)));
disp(append('b_fmt = ', cl_fix_format_to_string(b_fmt)));

% Define different data shapes to test
DATA_SHAPES = {100, [1,100], [100,1], [123,234], [12,34,56]};

disp('Starting tests...');
for i = 1:length(DATA_SHAPES)
    data_shape = DATA_SHAPES{i};
    fprintf(['\tTest %i of %i: data shape = ', repmat('%i ', 1, length(data_shape)), newline], ...
            i, length(DATA_SHAPES), data_shape);

    % Generate some random input data.
    a = cl_fix_random(data_shape, a_fmt);
    b = cl_fix_random(data_shape, b_fmt);

    % ---------------------------------------------------------------------------------------------
    % Example Arithmetic
    % ---------------------------------------------------------------------------------------------

    % Note: All of these examples get result formats from cl_fix_*_fmt functions. This means the
    % results are guaranteed to be represented without loss (no rounding or saturation).

    % Addition
    add_fmt = cl_fix_add_fmt(a_fmt, b_fmt);
    add_result = cl_fix_add(a, a_fmt, b, b_fmt, add_fmt);

    % Subtraction
    sub_fmt = cl_fix_sub_fmt(a_fmt, b_fmt);
    sub_result = cl_fix_sub(a, a_fmt, b, b_fmt, sub_fmt);

    % Add-sub
    addsub = logical(randi([0,1], size(a)));
    addsub_fmt = cl_fix_addsub_fmt(a_fmt, b_fmt);
    addsub_result = cl_fix_addsub(a, a_fmt, b, b_fmt, addsub, addsub_fmt);

    % Multiplication
    mult_fmt = cl_fix_mult_fmt(a_fmt, b_fmt);
    mult_result = cl_fix_mult(a, a_fmt, b, b_fmt, mult_fmt);

    % Absolute value
    abs_fmt = cl_fix_abs_fmt(a_fmt);
    abs_result = cl_fix_abs(a, a_fmt, abs_fmt);

    % Negative value
    neg_fmt = cl_fix_neg_fmt(a_fmt);
    neg_result = cl_fix_neg(a, a_fmt, neg_fmt);

    % Bit-shift
    shift_size = -3; % Negative value => right shift.
    shift_fmt = cl_fix_shift_fmt(a_fmt, shift_size);
    shift_result = cl_fix_shift(a, a_fmt, shift_size, shift_fmt);

    % ---------------------------------------------------------------------------------------------
    % Arithmetic Result Checking
    % ---------------------------------------------------------------------------------------------

    % All data formats in this script fit inside double-precision floats. This means we don't need
    % to handle arbitrary precision data.
    assert(~cl_fix_is_wide(a_fmt), 'Unexpected wide a_fmt.');
    assert(~cl_fix_is_wide(b_fmt), 'Unexpected wide b_fmt.');

    % Note: All of the example results are guaranteed to be represented without loss. So, we can
    % just check against ordinary double-precision arithmetic.

    % Addition
    assert(~cl_fix_is_wide(add_fmt), 'Unexpected wide add_fmt.');
    add_expected = a + b;
    assert(isequal(add_result, add_expected), 'Error in add');

    % Subtraction
    assert(~cl_fix_is_wide(sub_fmt), 'Unexpected wide sub_fmt.');
    sub_expected = a - b;
    assert(isequal(sub_result, sub_expected), 'Error in sub');

    % Add-sub
    assert(~cl_fix_is_wide(addsub_fmt), 'Unexpected wide addsub_fmt.');
    addsub_expected = sub_expected;
    addsub_expected(addsub) = add_expected(addsub);
    assert(isequal(addsub_result, addsub_expected), 'Error in addsub');

    % Multiplication
    assert(~cl_fix_is_wide(mult_fmt), 'Unexpected wide mult_fmt.');
    mult_expected = a .* b;
    assert(isequal(mult_result, mult_expected), 'Error in mult');

    % Absolute value
    assert(~cl_fix_is_wide(abs_fmt), 'Unexpected wide abs_fmt.');
    abs_expected = abs(a);
    assert(isequal(abs_result, abs_expected), 'Error in abs');

    % Negation
    assert(~cl_fix_is_wide(neg_fmt), 'Unexpected wide neg_fmt.');
    neg_expected = -a;
    assert(isequal(neg_result, neg_expected), 'Error in neg');

    % Bit-shifting
    assert(~cl_fix_is_wide(shift_fmt), 'Unexpected wide shift_fmt.');
    shift_expected = a * 2^shift_size;
    assert(isequal(shift_result, shift_expected), 'Error in shift');

    % ---------------------------------------------------------------------------------------------
    % Misc Functions
    % ---------------------------------------------------------------------------------------------

    % Here, we mostly just check that Python function calls succeed without error. Functionality of
    % the Python implementation is tested separately.

    % Rounding
    round = Round.ConvEven_s;
    round_fmt = cl_fix_round_fmt(a_fmt, a_fmt.F - 4, round);
    round_result = cl_fix_round(a, a_fmt, round_fmt, round);

    % Saturation
    saturate = Sat.Sat_s;
    sat_fmt = cl_fix_format(0, a_fmt.I - 4, a_fmt.F);
    sat_result = cl_fix_saturate(a, a_fmt, sat_fmt, saturate);

    % Rounding and saturation
    resize_result = cl_fix_resize(a, a_fmt, b_fmt, round, saturate);

    % Bit-width
    assert(cl_fix_width(a_fmt) == a_fmt.S + a_fmt.I + a_fmt.F, 'Unexpected a_fmt width.');
    assert(cl_fix_width(b_fmt) == b_fmt.S + b_fmt.I + b_fmt.F, 'Unexpected b_fmt width.');

    % Integer representations
    a_int = cl_fix_to_integer(a, a_fmt);
    a_check = cl_fix_from_integer(a_int, a_fmt);
    assert(isequal(a_check, a), 'Unexpected values after integer conversions.');

    % Conversion from float
    a_check = cl_fix_from_real(a, a_fmt, Sat.SatWarn_s);
    assert(isequal(a_check, a), 'Unexpected values after float conversions');

    % Max and min values
    a_max = cl_fix_max_value(a_fmt);
    a_min = cl_fix_min_value(a_fmt);
    b_max = cl_fix_max_value(b_fmt);
    b_min = cl_fix_min_value(b_fmt);

    % Range checks
    inrange_result = cl_fix_in_range(a, a_fmt, b_fmt);

    % Generating zeros
    zeros_a = cl_fix_zeros(data_shape, a_fmt);
    zeros_b = cl_fix_zeros(data_shape, b_fmt);
end

disp('Success: All tests passed.');

classdef wide
    % ------------------------------------------------------------------------------
    % This class provides functions to support "wide" (arbitrary-precision)
    % fixed-point numbers. These functions require MATLAB's Fixed-Point Designer
    % toolbox.
    %
    % For ordinary "narrow" fixed-point numbers (<= 53 bits), the Fixed-Point
    % Designer toolbox is not required.
    % ------------------------------------------------------------------------------

    % =============================================================================================
    % PUBLIC METHODS
    % =============================================================================================
    methods (Static = true)
        function y = py2mat(x, x_fmt)
            % ------------------------------------------------------------------------------
            % function y = py2mat(x, x_fmt)
            % ------------------------------------------------------------------------------
            % Converts Python data types to MATLAB types, with wide fixed-point support.
            % ------------------------------------------------------------------------------
            if cl_fix_is_wide(x_fmt)
                % Wide fixed-point conversion from Python to MATLAB fi()
                y = wide.py2fi(x, x_fmt);
            else
                % Narrow fixed-point (float)
                y = py2mat(x);
            end
        end

        function y = mat2py(x, x_fmt)
            % ------------------------------------------------------------------------------
            % function y = mat2py(x, x_fmt)
            % ------------------------------------------------------------------------------
            % Converts MATLAB data types to Python types, with wide fixed-point support.
            % ------------------------------------------------------------------------------
            if cl_fix_is_wide(x_fmt)
                % Wide fixed-point conversion from MATLAB fi() to Python
                y = wide.fi2py(x);
            else
                % Narrow fixed-point (float)
                y = mat2py(x);
            end
        end

        function [s,w,f,i] = fmt2swf(fmt)
            % ------------------------------------------------------------------------------
            % function [s,w,f,i] = fmt2swf(fmt)
            % ------------------------------------------------------------------------------
            % Converts en_cl_fix FixFormat [s,i,f] to MATLAB fi() [s,w,f] parameterization.
            % ------------------------------------------------------------------------------
            s = double(fmt.S);
            w = double(cl_fix_width(fmt));
            f = double(fmt.F);
            i = double(fmt.I);
        end

        function [s,w,f,i] = fi2swf(x)
            % ------------------------------------------------------------------------------
            % function [s,w,f,i] = fi2swf(x)
            % ------------------------------------------------------------------------------
            % Extracts [s,w,f] parameterization from MATLAB fi() object.
            % ------------------------------------------------------------------------------
            s = issigned(x);
            w = x.WordLength;
            f = x.FractionLength;
            i = w-f-s;
        end

        function fmt = swf2fmt(s, w, f)
            % ------------------------------------------------------------------------------
            % function fmt = swf2fmt(s, w, f)
            % ------------------------------------------------------------------------------
            % Converts MATLAB fi() [s,w,f] parameterization to en_cl_fix FixFormat [s,i,f].
            % ------------------------------------------------------------------------------
            fmt = cl_fix_format(s, w-f-s, f);
        end

        function fmt = fi2fmt(x)
            % ------------------------------------------------------------------------------
            % function fmt = fi2fmt(x)
            % ------------------------------------------------------------------------------
            % Extracts en_cl_fix FixFormat [s,i,f] from MATLAB fi() object.
            % ------------------------------------------------------------------------------
            [s, w, f] = wide.fi2swf(x);
            fmt = wide.swf2fmt(s, w, f);
        end
    end

    % =============================================================================================
    % PRIVATE METHODS
    % =============================================================================================
    methods (Static = true, Access = private)
        function y = py2fi(x, x_fmt)
            % ------------------------------------------------------------------------------
            % function y = py2fi(x, x_fmt)
            % ------------------------------------------------------------------------------
            % Converts "wide" (arbitrary-precision) fixed-point Python data to MATLAB fi().
            % ------------------------------------------------------------------------------

            % Convert wide (arbitrary-precision) fixed-point data to uint64s
            x = py.en_cl_fix_pkg.to_uint64_array(x, x_fmt);

            % The uint64s are expanded along an extra dimension. If w<=64, then that dimension is
            % a singleton and will be lost in MATLAB. Therefore, we record ndim now.
            ndim = x.ndim - 1;

            % Convert to native MATLAB type
            x = uint64(x);

            % Convert fmt from FixFormat to fi() [s,w,f] parameterization
            [s,w,f] = wide.fmt2swf(x_fmt);

            % Concatenate 64-bit integers
            n_ints = size(x, ndim+1);
            x = fi(x, 0, w, 0);
            idx = repmat({':'}, ndim+1, 1);  % Ugly indexing trick to slice n-D array.
            idx{end} = 1;  % Select the first slice (64 LSBs).
            y = x(idx{:});
            y.SumMode = 'KeepLSB';
            y.SumWordLength = w;
            for k = 2:n_ints
                idx{end} = k;  % Select the kth slice (64 bits).
                y = y + pow2(x(idx{:}), (k-1)*64);
            end

            % Reinterpret fixed-point format
            y = reinterpretcast(y, numerictype(s,w,f));
            y.SumMode = 'FullPrecision';
        end

        function y = fi2py(x)
            % ------------------------------------------------------------------------------
            % function y = fi2py(x)
            % ------------------------------------------------------------------------------
            % Converts MATLAB fi() to "wide" (arbitrary-precision) fixed-point Python data.
            % ------------------------------------------------------------------------------
            fmt = wide.fi2fmt(x);
            w = cl_fix_width(fmt);

            % Calculate number of uint64s needed per element
            n_ints = ceil(w / 64);

            % Cast data to unsigned integer
            x = reinterpretcast(x, numerictype(0,w,0));

            % Populate uint64 array
            ndim = ndims(x);
            shape = [size(x), n_ints];  % Create new dimension for stacking uint64s.
            y = zeros(shape, 'uint64');
            idx = repmat({':'}, ndim+1, 1);  % Ugly indexing trick to slice n-D array.
            x.RoundingMethod = 'Floor';
            for k = 1:n_ints
                idx{end} = k;  % Write the kth slice (64 bits).
                y(idx{:}) = uint64(quantize(x, numerictype(0, 64, 0)));
                x = pow2(x, -64);  % x >>= 64.
            end

            % Convert uint64s to wide (arbitrary-precision) fixed-point data
            y = mat2py(y);
            y = py.en_cl_fix_pkg.from_uint64_array(y, fmt);
        end
    end
end

% Convert a MATLAB variable to an equivalent Python-native variable.
% py_var = mat2py(mat_var);
% py_var = mat2py(mat_var, 'bytes');  % char mapped to Python bytes
% py_var = mat2py(mat_var, 'string'); % char mapped to Python string
function [x_py] = mat2py(x_mat, char_to)
    arguments
        x_mat
        char_to = 'string';
    end

% {{{ code/matlab_py/mat2py.m
% This code accompanies the book _Python for MATLAB Development:
% Extend MATLAB with 300,000+ Modules from the Python Package Index_
