% DOI 10.1007/978-1-4842-7223-7
% https://github.com/Apress/python-for-matlab-development
%
% Copyright © 2022-2023 Albert Danial
%
% Contributions by:
%   - https://github.com/hcommin (performance enhancements)
%
% MIT License:
% Permission is hereby granted, free of charge, to any person obtaining a copy
% of this software and associated documentation files (the "Software"), to deal
% in the Software without restriction, including without limitation the rights
% to use, copy, modify, merge, publish, distribute, sublicense, and/or sell
% copies of the Software, and to permit persons to whom the Software is
% furnished to do so, subject to the following conditions:
%
% The above copyright notice and this permission notice shall be included in
% all copies or substantial portions of the Software.
%
% THE SOFTWARE IS PROVIDED “AS IS”, WITHOUT WARRANTY OF ANY KIND, EXPRESS OR
% IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,
% FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL
% THE AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER
% LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING
% FROM, OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER
% DEALINGS IN THE SOFTWARE.
% }}}

    x_py = py.numpy.array({});
    switch class(x_mat)
        case 'char'
            if strcmp(char_to,'bytes')
                x_py = py.bytes(x_mat,'ASCII');
            else
                x_py = py.str(x_mat);
            end
        case 'string'
            x_py = py.str(x_mat);
        case 'datetime'
            int_sec = int64(floor(x_mat.Second));
            frac_sec = x_mat.Second - double(int_sec);
            micro_sec = int64(round(1e6 * frac_sec));
            if ~isempty(x_mat.TimeZone)
                tzinfo = py.dateutil.tz.gettz(x_mat.TimeZone);
            else
                tzinfo = py.None;
            end
            x_py = py.datetime.datetime(int64(x_mat.Year), int64(x_mat.Month), ...
                               int64(x_mat.Day) , int64(x_mat.Hour) , ...
                               int64(x_mat.Minute), int_sec, ...
                               micro_sec, tzinfo);
        case {'double', 'single', ...
              'uint8', 'uint16', 'uint32', 'uint64', ...
              'int8',  'int16',  'int32',  'int64'}
            if issparse(x_mat)
                if ndims(x_mat) ~= 2
                    fprintf('mat2py:  can only convert 2D sparse matrices\n')
                    return
                end
                [nR,nC] = size(x_mat);
                [i,j,vals] = find(x_mat);
                % subtract 1 to go from 1-based to 0-based indices
                py_I    = py.numpy.array(int64(i)-1);
                py_J    = py.numpy.array(int64(j)-1);
                py_vals = mat2py(vals);
                py_dims = py.tuple({int64(nR), int64(nC)});
                py_IJ   = py.tuple({py_I, py_J});
                V_IJ    = py.tuple({py_vals, py_IJ});
                x_py = py.scipy.sparse.coo_matrix(V_IJ,py_dims);
            else
                if numel(x_mat) == 1
                    x_py = x_mat;  % scalar numeric value
                elseif isreal(x_mat)
                    x_py = py.numpy.array(x_mat);
                else
                    x_py = py.numpy.array(real(x_mat)) + 1j*py.numpy.array(imag(x_mat));
                end
            end
        case 'logical'
            if x_mat
                x_py = py.True;
            else
                x_py = py.False;
            end
        case 'cell'
            x_py = py.list();
            dims = size(x_mat);
            if prod(dims) == max(size(x_mat))
                % 1D cell array
                for i = 1:numel(x_mat)
                    x_py.append(mat2py(x_mat{i}, char_to));
                end
            else
                if length(dims) > 2
                    fprintf('mat2py:  %d-dimensional cell array conversion ' + ...
                            'is not implemented\n', length(dims));
                    return
                end
                nR = dims(1,1); nC = dims(1,2);
                for r = 1:nR
                    this_row = py.list();
                    for c = 1:nC
                      this_row.append(mat2py(x_mat{r,c}, char_to));
                    end
                    x_py.append(this_row);
                end
            end
        case 'struct'
            x_py = py.dict();
            F = fieldnames(x_mat);
            if (length(x_mat) > 1) && ...
               (class(x_mat) == "struct")
                % struct array
                x_py = py.list();
                for j = 1:length(x_mat)
                    x_py.append( mat2py(x_mat(j)) );
                end
            else
                for i = 1:length(F)
                    if (length(x_mat.(F{i})) > 1) && ...
                       (class(x_mat.(F{i})) == "struct")
                        % struct of struct array
                        List = py.list();
                        for j = 1:length(x_mat.(F{i}))
                            List.append( mat2py(x_mat.(F{i})(j)) );
                        end
                        x_py.update(pyargs(F{i}, List));
                    else
                        x_py.update(pyargs(F{i}, mat2py(x_mat.(F{i}))));
                    end
                end
            end
        otherwise
            fprintf('mat2py:  %s conversion is not implemented\n', class(x_mat))
    end % switch
end

% Convert a native Python variable to an equivalent native MATLAB variable.

% {{{ code/matlab_py/py2mat.m   v 1.3  2023-09-15
% This code accompanies the book _Python for MATLAB Development:
% Extend MATLAB with 300,000+ Modules from the Python Package Index_
% ISBN 978-1-4842-7222-0 | ISBN 978-1-4842-7223-7 (eBook)
% DOI 10.1007/978-1-4842-7223-7
% https://github.com/Apress/python-for-matlab-development
%
% Copyright © 2022-2023 Albert Danial
%
% Contributions by:
%   - https://github.com/hcommin (performance enhancements)
%
% MIT License:
% Permission is hereby granted, free of charge, to any person obtaining a copy
% of this software and associated documentation files (the "Software"), to deal
% in the Software without restriction, including without limitation the rights
% to use, copy, modify, merge, publish, distribute, sublicense, and/or sell
% copies of the Software, and to permit persons to whom the Software is
% furnished to do so, subject to the following conditions:
%
% The above copyright notice and this permission notice shall be included in
% all copies or substantial portions of the Software.
%
% THE SOFTWARE IS PROVIDED “AS IS”, WITHOUT WARRANTY OF ANY KIND, EXPRESS OR
% IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,
% FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL
% THE AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER
% LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING
% FROM, OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER
% DEALINGS IN THE SOFTWARE.
% }}}
function [x_mat] = py2mat(x_py)
  switch class(x_py)
      % MATLAB types
      case {'logical', 'double', 'datetime'}
        x_mat = x_py;

      % Python dictionaries
      case 'py.dict'
      try
        % the obvious dict -> struct conversion only works
        % if the key string can be a MATLAB variable
        x_mat = struct(x_py);
      catch EO
        % A failure most likely means a Python key is not
        % a proper MATLAB variable name.  Go through them
        % individually
        key_index = int64(0);
        key_list = cell(py.list(x_py.keys()))
        for key = key_list
          key_index = key_index + 1;
          if class(key) == 'cell'
            % key could be a Python number
            v_name = string(py.str(key{1}));
          else
            v_name = string(key);
          end
          if isvarname(v_name)
            x_mat.(v_name) = x_py.get(key_list{key_index});
          else
            % this key can't be used; replace it
            fixed = sprintf('K%06d_', key_index) + ...
                    regexprep(v_name,'\W','_');
            x_mat.(fixed) = x_py.get(key_list{key_index});
          end
        end
      end
      fields = fieldnames(x_mat);
      for i = 1:length(fields)
        new_var = py2mat(x_mat.(fields{i}));
        x_mat = setfield(x_mat,fields{i}, new_var);
      end

    % NumPy arrays and typed scalars
    case 'py.numpy.ndarray'
      switch string(x_py.dtype.name)
        case "float64"
          x_mat = x_py.double;
        case "float32"
          x_mat = x_py.single;
        case "float16"
          % doesn't exist in matlab, upcast to float32
          x_mat = single(x_py.astype('float32'));
        % only reals and logicals can be cast to arrays so
        % have to cast the rest to either single or double
        case "uint8"
          x_mat = uint8(x_py.astype('float32'));
        case "int8"
          x_mat = int8(x_py.astype('float32'));
        case "uint16"
          x_mat = uint16(x_py.astype('float32'));
        case "int16"
          x_mat = int16(x_py.astype('float32'));
        case "uint32"
          x_mat = uint32(x_py.astype('float32'));
        case "int32"
          x_mat = int32(x_py.astype('float32'));
        case "uint64"
          x_mat = uint64(x_py.astype('float64'));
        case "int64"
          x_mat = int64(x_py.astype('float64'));
        case "bool"
          x_mat = logical(x_py);
        % Complex types require a math operation to coerce the
        % real and imaginary components to contiguous arrays.
        % Use "+0" for minimal performance impact.  Without this,
        % complex creation fails with
        %   Python Error: ValueError: ndarray is not contiguous
        case "complex64"
          x_mat = complex(single(x_py.real+0), single(x_py.imag+0));
        case "complex128"
          x_mat = complex(double(x_py.real+0), double(x_py.imag+0));
        case "complex256"
          fprintf('py2mat:  MATLAB does not support quad precision complex\n')
          x_mat = [];
          return
        otherwise
          % gets here with np.float16, custom dtypes
          fprintf('py2mat: %s not recognized\n', ...
                  string(x_py.dtype.name));
          x_mat = [];
          return
      end

    % Scipy sparse matrices
    case {'py.scipy.sparse.coo.coo_matrix', ...
          'py.scipy.sparse.csr.csr_matrix', ...
          'py.scipy.sparse.csc.csc_matrix', ...
          'py.scipy.sparse.dok.dok_matrix', ...
          'py.scipy.sparse.bsr.bsr_matrix', ...
          'py.scipy.sparse.dia.dia_matrix', ...
          'py.scipy.sparse.lil.lil_matrix', }
      ndims = x_py.get_shape();
      if length(ndims) ~= 2
          fprintf('py2mat:  can only convert 2D sparse matrices\n')
          x_mat = [];
          return
      end
      nR = int64(ndims{1});
      nC = int64(ndims{2});
      x_py = x_py.tocoo();
      values = py2mat(x_py.data);
      if isempty(values)
          % gets here if trying to convert a complex256 sparse matrix
          return
      end
      % add 1 to row & col indices to go from 0-based to 1-based
      x_mat = sparse(single(x_py.row)+1, single(x_py.col)+1, values, nR, nC);

    % Python sets, tuples, and lists
    case {'cell', 'py.tuple', 'py.list'}
      [nR, nC] = size(x_py);
      x_mat = cell(nR,nC);
      for r = 1:nR
        for c = 1:nC
          x_mat{r,c} = py2mat(x_py{r,c});
        end
      end

    % Python strings
    case 'py.str'
      x_mat = string(x_py);

    % Python integers
    case 'py.int'
      x_mat = x_py.int64;

    case 'py.datetime.datetime'
      x_mat = datetime(int64(x_py.year),  ...
                       int64(x_py.month), ...
                       int64(x_py.day),   ...
                       int64(x_py.hour),  ...
                       int64(x_py.minute),...
                       int64(x_py.second),...
                       double(x_py.microsecond)/1000.0);

    case 'py.bytes'
      x_mat = uint8(x_py);

    case 'py.NoneType'
      x_mat = '';

    case 'py.scipy.optimize.optimize.OptimizeResult'
      for k = cell(py.list(x_py.keys))
          x_mat.(string(k{1})) = py2mat(x_py.get(k{1}));
      end

    % punt
    otherwise
      % return the original item?  nothing?
      fprintf('py2mat: type "%s" not recognized\n', ...
              string(class(x_py)));
      x_mat = [];
  end
end

