46	else
47	    if strcmp(pe.Status, 'NotLoaded')
48	        pe = pyenv(ExecutionMode='InProcess');
49	    else
50	        if strcmp(pe.ExecutionMode, 'OutOfProcess')
51	            error('MATLAB must be restarted to change the Python environment');
52	        end
53	    end
