69	addpath(fullfile(root, '..', '..', 'models', 'matlab'));
70	
71	% -------------------------------------------------------------------------------------------------
72	% Example Setup
73	% -------------------------------------------------------------------------------------------------
74	
75	% Load shorthand constants
76	cl_fix_constants;
77	
78	% Specify some input data formats.
79	a_fmt = cl_fix_format(1, 50, 65);
80	b_fmt = cl_fix_format(0, 52, 56);
81	
82	% Check string conversion functions
83	disp(append('a_fmt = ', cl_fix_format_to_string(a_fmt)));
84	disp(append('b_fmt = ', cl_fix_format_to_string(b_fmt)));
85	
86	% Define different data shapes to test
87	DATA_SHAPES = {100, [1,100], [100,1], [123,234], [12,34,56]};
88	
89	disp('Starting tests...');
90	for i = 1:length(DATA_SHAPES)
91	    data_shape = DATA_SHAPES{i};
92	    fprintf(['\tTest %i of %i: data shape = ', repmat('%i ', 1, length(data_shape)), newline], ...
93	            i, length(DATA_SHAPES), data_shape);
94	
95	    % Generate some random input data.
96	    a = cl_fix_random(data_shape, a_fmt);
97	    b = cl_fix_random(data_shape, b_fmt);
98	    
99	    % ---------------------------------------------------------------------------------------------
100	    % Example Arithmetic
101	    % ---------------------------------------------------------------------------------------------
102	    
103	    % Note: All of these examples get result formats from cl_fix_*_fmt functions. This means the
104	    % results are guaranteed to be represented without loss (no rounding or saturation).
105	    
106	    % Addition
107	    add_fmt = cl_fix_add_fmt(a_fmt, b_fmt);
108	    add_result = cl_fix_add(a, a_fmt, b, b_fmt, add_fmt);
