116	    addsub_fmt = cl_fix_addsub_fmt(a_fmt, b_fmt);
117	    addsub_result = cl_fix_addsub(a, a_fmt, b, b_fmt, addsub, addsub_fmt);
118	    
119	    % Multiplication
120	    mult_fmt = cl_fix_mult_fmt(a_fmt, b_fmt);
121	    mult_result = cl_fix_mult(a, a_fmt, b, b_fmt, mult_fmt);
122	    
123	    % Absolute value
124	    abs_fmt = cl_fix_abs_fmt(a_fmt);
125	    abs_result = cl_fix_abs(a, a_fmt, abs_fmt);
126	    
127	    % Negative value
128	    neg_fmt = cl_fix_neg_fmt(a_fmt);
129	    neg_result = cl_fix_neg(a, a_fmt, neg_fmt);
130	    
131	    % Bit-shift
132	    shift_size = -3; % Negative value => right shift.
133	    shift_fmt = cl_fix_shift_fmt(a_fmt, shift_size);
134	    shift_result = cl_fix_shift(a, a_fmt, shift_size, shift_fmt);
135	    
136	    % ---------------------------------------------------------------------------------------------
137	    % Arithmetic Result Checking
138	    % ---------------------------------------------------------------------------------------------
139	    
140	    % None of the data formats in this script fit inside double-precision floats. This means we
141	    % need to handle arbitrary precision data.
142	    assert(cl_fix_is_wide(a_fmt), 'Unexpected narrow a_fmt.');
143	    assert(cl_fix_is_wide(b_fmt), 'Unexpected narrow b_fmt.');
144	    
145	    % Note: All of the example results are guaranteed to be represented without loss. So, we can
146	    % just check against ordinary double-precision arithmetic.
147	    
148	    % Addition
149	    assert(cl_fix_is_wide(add_fmt), 'Unexpected narrow add_fmt.');
150	    add_expected = a + b;
151	    assert(isequal(add_result, add_expected), 'Error in add');
152	    
153	    % Subtraction
154	    assert(cl_fix_is_wide(sub_fmt), 'Unexpected narrow sub_fmt.');
155	    sub_expected = a - b;
156	    assert(isequal(sub_result, sub_expected), 'Error in sub');
157	    
158	    % Add-sub
159	    assert(cl_fix_is_wide(addsub_fmt), 'Unexpected narrow addsub_fmt.');
160	    addsub_expected = sub_expected;
161	    addsub_expected(addsub) = add_expected(addsub);
162	    assert(isequal(addsub_result, addsub_expected), 'Error in addsub');
163	    
164	    % Multiplication
165	    assert(cl_fix_is_wide(mult_fmt), 'Unexpected narrow mult_fmt.');
166	    mult_expected = a .* b;
167	    assert(isequal(mult_result, mult_expected), 'Error in mult');
168	    
169	    % Absolute value
170	    assert(cl_fix_is_wide(abs_fmt), 'Unexpected narrow abs_fmt.');
171	    abs_expected = abs(a);
172	    assert(isequal(abs_result, abs_expected), 'Error in abs');
173	    
174	    % Negation
175	    assert(cl_fix_is_wide(neg_fmt), 'Unexpected narrow neg_fmt.');
176	    neg_expected = -a;
177	    assert(isequal(neg_result, neg_expected), 'Error in neg');
178	    
179	    % Bit-shifting
180	    assert(cl_fix_is_wide(shift_fmt), 'Unexpected narrow shift_fmt.');
181	    shift_expected = a * 2^shift_size;
182	    assert(isequal(shift_result, shift_expected), 'Error in shift');
183	    
184	    % ---------------------------------------------------------------------------------------------
185	    % Misc Functions
186	    % ---------------------------------------------------------------------------------------------
187	    
188	    % Here, we mostly just check that Python function calls succeed without error. Functionality of
189	    % the Python implementation is tested separately.
190	    
191	    % Rounding
192	    round = Round.ConvEven_s;
193	    round_fmt = cl_fix_round_fmt(a_fmt, a_fmt.F - 4, round);
194	    round_result = cl_fix_round(a, a_fmt, round_fmt, round);
195	    
196	    % Saturation
197	    saturate = Sat.Sat_s;
198	    sat_fmt = cl_fix_format(0, a_fmt.I - 4, a_fmt.F);
199	    sat_result = cl_fix_saturate(a, a_fmt, sat_fmt, saturate);
200	    
201	    % Rounding and saturation
202	    resize_result = cl_fix_resize(a, a_fmt, b_fmt, round, saturate);
203	    
204	    % Bit-width
205	    assert(cl_fix_width(a_fmt) == a_fmt.S + a_fmt.I + a_fmt.F, 'Unexpected a_fmt width.');
206	    assert(cl_fix_width(b_fmt) == b_fmt.S + b_fmt.I + b_fmt.F, 'Unexpected b_fmt width.');
207	    
208	    % Integer representations
209	    a_int = cl_fix_to_integer(a, a_fmt);
210	    a_check = cl_fix_from_integer(a_int, a_fmt);
211	    assert(isequal(a_check, a), 'Unexpected values after integer conversions.');
212	    
213	    % Conversion from float
214	    narrow_fmt = cl_fix_format(a_fmt.S, a_fmt.I, 53 - a_fmt.S - a_fmt.I);
215	    narrow_data = cl_fix_random(data_shape, narrow_fmt);
216	    a_check = cl_fix_from_real(narrow_data, a_fmt, Sat.SatWarn_s);
217	    assert(isequal(a_check, narrow_data), 'Unexpected values after float conversions');
218	    
219	    % Max and min values
220	    a_max = cl_fix_max_value(a_fmt);
221	    a_min = cl_fix_min_value(a_fmt);
222	    b_max = cl_fix_max_value(b_fmt);
223	    b_min = cl_fix_min_value(b_fmt);
224	    
225	    % Range checks
226	    inrange_result = cl_fix_in_range(a, a_fmt, b_fmt);
227	    
228	    % Generating zeros
229	    zeros_a = cl_fix_zeros(data_shape, a_fmt);
230	    zeros_b = cl_fix_zeros(data_shape, b_fmt);
231	end
232	
233	disp('Success: All tests passed.');
